"use client";

import { useEffect, useState } from "react";
import { supabase } from "@/lib/supabase";
import { useRouter } from "next/navigation";
import NavBar from "@/components/NavBar";
import { FileText, ArrowRight } from "lucide-react";

export default function HistoryPage() {
  const router = useRouter();
  const [analyses, setAnalyses] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!supabase) {
      setLoading(false);
      return;
    }

    const fetchHistory = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        router.push("/login");
        return;
      }

      const { data, error } = await supabase
        .from('analyses')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

      if (data) setAnalyses(data);
      setLoading(false);
    };

    fetchHistory();
  }, [router]);

  return (
    <main className="min-h-screen bg-background flex flex-col">
      <NavBar />
      <div className="flex-1 max-w-6xl w-full mx-auto px-6 py-24 mt-10">
        <h1 className="text-3xl font-heading font-bold mb-8">Past Analyses</h1>

        {loading ? (
          <p className="text-muted">Loading history...</p>
        ) : !supabase ? (
          <div className="glass-card p-8 border-rose-500/20 text-rose-500">
            Supabase is not configured. Add your environment variables to view history.
          </div>
        ) : analyses.length === 0 ? (
          <div className="glass-card p-12 text-center text-muted">
            <FileText className="w-12 h-12 mx-auto mb-4 opacity-50" />
            <p>You haven't run any resume analyses yet.</p>
            <button onClick={() => router.push("/upload")} className="mt-4 text-primary-500 font-medium">
              Run your first analysis ΓåÆ
            </button>
          </div>
        ) : (
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {analyses.map(item => (
              <div key={item.id} className="glass-card p-6 flex flex-col hover:-translate-y-1 transition-transform cursor-pointer"
                onClick={() => {
                  sessionStorage.setItem("lastAnalysisResult", JSON.stringify(item.data));
                  router.push("/analysis");
                }}
              >
                <div className="flex justify-between items-start mb-4">
                  <h3 className="font-bold font-heading truncate flex-1 pr-4" title={item.file_name}>{item.file_name}</h3>
                  <span className="text-primary-500 font-bold bg-primary-500/10 px-2 py-1 rounded text-sm shrink-0">
                    {item.data?.overall_score || 0}%
                  </span>
                </div>
                <div className="text-sm text-muted mb-4 flex-1 line-clamp-2">
                  Target Role: {item.job_description ? "Custom Job Description" : "General Analysis"}
                </div>
                <div className="flex justify-between items-center text-xs text-muted border-t border-border pt-4 mt-auto">
                  <span>{new Date(item.created_at).toLocaleDateString()}</span>
                  <span className="flex items-center gap-1 text-primary-500 font-medium">View Report <ArrowRight className="w-3 h-3"/></span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </main>
  );
}

"use client";

import NavBar from "@/components/NavBar";
import UploadZone from "@/components/UploadZone";
import { ArrowRight, BrainCog } from "lucide-react";
import Link from "next/link";
import { useState } from "react";
import { useRouter } from "next/navigation";

export default function UploadPage() {
  const router = useRouter();
  const [file, setFile] = useState<File | null>(null);
  const [jd, setJd] = useState("");
  const [isAnalyzing, setIsAnalyzing] = useState(false);

  const handleAnalyze = async () => {
    if (!file) {
      alert("Please upload a resume file first.");
      return;
    }
    setIsAnalyzing(true);
    try {
      // Lazy load to prevent hydration issues with pdfjs worker
      const { extractTextFromFile } = await import("@/utils/resumeParser");
      const text = await extractTextFromFile(file);

      if (text.length < 50) {
        throw new Error("Could not extract enough text from the document. Please ensure the PDF/DOCX has text, not just images.");
      }

      const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ resumeText: text, jobDescription: jd })
      });

      if (!response.ok) {
        const err = await response.json();
        throw new Error(err.error || "Failed to analyze resume.");
      }

      const data = await response.json();

      // Attempt to save to Supabase history if configured and user is logged in
      try {
        const { supabase } = await import("@/lib/supabase");
        if (supabase) {
          const { data: { user } } = await supabase.auth.getUser();
          if (user) {
            await supabase.from('analyses').insert({
              user_id: user.id,
              file_name: file.name,
              job_description: jd,
              data: data
            });
          }
        }
      } catch (supeErr) {
        console.error("Could not save to history", supeErr);
      }

      sessionStorage.setItem("lastAnalysisResult", JSON.stringify(data));

      router.push("/analysis");
    } catch (error: unknown) {
      const errMsg = error instanceof Error ? error.message : "An unexpected error occurred.";
      alert(errMsg);
      setIsAnalyzing(false);
    }
  };

  return (
    <main className="flex flex-col min-h-screen bg-background">
      <NavBar />

      <div className="flex-1 max-w-4xl w-full mx-auto px-6 py-24 mt-10">
        <div className="mb-10 text-center">
          <h1 className="text-4xl font-heading font-bold mb-4">Analyze Your Resume</h1>
          <p className="text-muted text-lg">Upload your resume and optionally paste a job description. Our AI will identify skill gaps and provide powerful salary negotiation insights.</p>
        </div>

        <div className="space-y-8">
          <div className="glass-card p-6 md:p-8">
            <h2 className="text-xl font-heading font-bold mb-4">1. Upload Resume</h2>
            <UploadZone onFileSelect={setFile} onClear={() => setFile(null)} />
          </div>

          <div className="glass-card p-6 md:p-8">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-heading font-bold">2. Job Description <span className="text-sm font-normal text-muted">(Optional but Recommended)</span></h2>
            </div>
            <textarea 
              value={jd}
              onChange={(e) => setJd(e.target.value)}
              placeholder="Paste the target job description here to receive an accurate ATS match and keyword gap analysis..."
              className="w-full min-h-[160px] p-4 rounded-xl border border-border bg-background focus:ring-2 focus:ring-primary-500/50 focus:border-primary-500 outline-none transition-all resize-y text-sm text-foreground"
            />
          </div>

          <div className="pt-4 flex justify-end">
            <button
              onClick={handleAnalyze}
              disabled={!file || isAnalyzing}
              className="flex items-center gap-2 bg-primary-500 hover:bg-primary-600 disabled:bg-primary-500/50 disabled:cursor-not-allowed text-white px-8 py-4 rounded-full font-medium transition-all shadow-lg shadow-primary-500/20"
            >
              {isAnalyzing ? (
                <>
                  <BrainCog className="w-5 h-5 animate-spin" /> Analyzing via Claude...
                </>
              ) : (
                <>
                  Generate Free Report <ArrowRight className="w-5 h-5" />
                </>
              )}
            </button>
          </div>
        </div>
      </div>
    </main>
  );
}
